def solve(arg1: dict) -> int:
    challenge_id = arg1.get('challengeId')

    if not challenge_id:
        return 'Error: Challenge ID is required'

    # Mock data for reviewers and submissions
    reviewers = {
        '12345': ['reviewer1', 'reviewer2'],
        '67890': ['reviewer3']
    }

    submissions = {
        'reviewer1': {'challengeId': '12345', 'submitted': True},
        'reviewer2': {'challengeId': '12345', 'submitted': False},
        'reviewer3': {'challengeId': '67890', 'submitted': True}
    }

    if challenge_id not in reviewers:
        return 'Error: Challenge not found'

    total_reviewers = len(reviewers[challenge_id])
    total_submissions = sum(1 for reviewer in reviewers[challenge_id] if submissions.get(reviewer, {}).get('submitted', False))

    if total_reviewers == 0:
        return 0

    progress_percentage = (total_submissions / total_reviewers) * 100
    return round(progress_percentage, 2)
